CREATE OR REPLACE FUNCTION fpa_com_member_eng_name (as_memno char) RETURNS varchar AS $body$
DECLARE

  ls_name varchar(100);

BEGIN
  select  eng_name into STRICT ls_name
  from    sc_mem_m_membership_registered
  where (membership_no = as_memno);

return   trim(both ls_name);
exception when others then CALL spa_dberror('FPA_COM_MEMBER_ENG_NAME');return null;
END;
